var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"우걱우걱…….","JPN":"もぐもぐ……","ENG":"*Munch* *Munch*","TWN":"嚼嚼嚼……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"도대체 얘는 왜 같이 데려오라고 한 거예요?","JPN":"どうしてこの子を連れて来させたんですか？","ENG":"Why exactly did you bring her along?","TWN":"到底為什麼要帶上她一起？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"성황청이나 기관을 건드리면 안 된다고 말한 건 언니잖아요.","JPN":"聖皇庁や機関に手を出してはいけないと言ったのは姉さんでしょう。","ENG":"You're the one who told me not to mess with the Holy Curia or any organizations.","TWN":"說不能碰聖皇廳或機構的不是姊姊嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"길 잃은 어린 양을 사랑하라. 뭐 이런 거예요?","JPN":"迷える子羊を慈しめとか、そういうことですか？","ENG":"Is this some love-the-lost-little-lamb kind of thing?","TWN":"愛護迷路的小羊，是這樣嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럴 리가 있겠어?","JPN":"そんなわけないでしょう？","ENG":"As if.","TWN":"怎麼可能呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"받을 게 있어서 부른 것뿐이야.","JPN":"受け取るものがあるから呼んだだけよ。","ENG":"I called her because she has something I need.","TWN":"只是因為有東西要拿才叫她來的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"창백한 달 감염자는 피 말고는 안 먹는다면서요? 저건 엄청나게 잘 먹는데.","JPN":"それに……青白い月の感染者は血しか飲めないって言ってたのに。あれはめちゃくちゃ食べてるじゃないですか。","ENG":"I heard the Pale Moon affected only drank blood. But she's eating a ton of egg tarts…?","TWN":"不是說蒼月感染者只喝血嗎？那傢伙吃得可香了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"설마 에그타르트에 이상한 주술 같은 거 걸어둔 건 아니죠?","JPN":"まさか、エッグタルトに変な呪術をかけたりしてませんよね？","ENG":"You didn't... put some weird spell on those egg tarts, did you?","TWN":"不會是在蛋撻上施了什麼奇怪的法術吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럴 리가 없잖아.","JPN":"まさか。","ENG":"Of course not.","TWN":"怎麼可能呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"다만…….","JPN":"ただ……","ENG":"Well...","TWN":"只是……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"다만?","JPN":"ただ？","ENG":"Well?","TWN":"只是？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"에그타르트에서 불량식품의 냄새가 나요!","JPN":"エッグタルトからお菓子さんの匂いがします！","ENG":"This egg tart smells like Junk food!","TWN":"蛋撻裡有垃圾食物的味道！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L20_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무슨 방법으로 만드신 거죠?","JPN":"どうやって作ったんですか？","ENG":"What did you put in it?!","TWN":"你是用什麼方法做的？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"네 피를…… 좀 섞었지.","JPN":"あなたの血を……ちょっと入れたわ。","ENG":"A little bit of... your blood.","TWN":"用她的血……稍微混合了一些。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어쩐지, 다짜고짜 피를 뽑아가시더라니.","JPN":"どうりで、急に血を抜くと思ったら……","ENG":"Figures. No wonder you were so eager to take my blood.","TWN":"我說嘛，突然就抽我的血。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"미안~ 어쩔 수 없었어.","JPN":"ごめんね～仕方なかったの。","ENG":"Sorry! Had no other choice.","TWN":"抱歉～我沒有其他辦法。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"저거 봐, 햄스터처럼 먹고 있는 게 귀엽지 않니?","JPN":"ねえ、食べてる姿がまるでハムスターみたいで可愛くない？","ENG":"Look at her, though. Doesn't she look cute, stuffing her face like a little hamster?","TWN":"你看，她像倉鼠一樣吃東西的樣子是不是很可愛？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"누가 봐도 걸신들린 거지꼴인데요.","JPN":"どこからどう見ても物乞いのようにしか見えませんけど。","ENG":"She looks more like a starving vagrant.","TWN":"這是誰都能看出來的餓鬼模樣啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"웃…… 컥컥!","JPN":"うッ……ゲホゲホ！","ENG":"Ngh... *Cough*","TWN":"唔……咳咳！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"에휴, 마실 게 있는지 찾아보고 올게요.","JPN":"はあ……飲み物を持ってきますね。","ENG":"*Sigh* I'll go find something for you to drink.","TWN":"呼，我去看看有沒有什麼喝的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흠, 흠! 추한 모습을 보였군요. 사과드립니다.","JPN":"こ、こほん！　みっともない姿をお見せしてしまいましたね。お詫びします。","ENG":"Ahem! I have displayed unsightly behavior. I apologize.","TWN":"嗯，嗯！讓你見笑了。請見諒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이제 와서 예의 바른 척해 봐야 소용없어.","JPN":"今更礼儀正しいふりしても意味ないよ。","ENG":"Too late to act polite now.","TWN":"現在才裝禮貌也沒用了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"배부르게 먹였으니 이제 네 기억을 소거하고 성황청으로 돌려보낼 거야.","JPN":"お腹いっぱい食べさせたし、あんたの記憶を消去して聖皇庁に帰すから。","ENG":"Anyway, now that you're full, I'm wiping your memory and sending you back to the Holy Curia.","TWN":"吃飽了吧，現在我要抹去你的記憶，把你送回聖皇廳。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네? 서, 성황청으로 돌려보낸다고요?","JPN":"え？　せ、聖皇庁に帰す？","ENG":"What? Y-you're sending me back?!","TWN":"什麼？要把我送回聖皇廳嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"우리가 성황청이랑 척을 지면서 널 데리고 있을 이유가 없잖아.","JPN":"だって私たちが聖皇庁を敵に回してまであんたを保護する理由がないじゃない。","ENG":"Why would we risk pissing off the Holy Curia just to keep you around?","TWN":"我們沒有理由在與聖皇廳交惡的情況下還帶著你。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"전 성황청 그만뒀는데요?","JPN":"私は聖皇庁辞めましたよ？","ENG":"I already quit.","TWN":"我已經退出聖皇廳了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L47_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"거기가 무슨 학원인 줄 알아? 돌아가라면 돌아가!","JPN":"聖皇庁が塾か！　帰れっつったら帰れ！","ENG":"What, you think it's a school club? If I say go back, you go back.","TWN":"你以為那裡是學校嗎？我叫你回去就回去！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 네가 빨아먹은 피는 청구할 거니까 그렇게 알아둬.","JPN":"あ、でもあんたが飲んだ血の代金は請求するから。","ENG":"Oh, and I'll be billing you for the blood you drank.","TWN":"啊，我會把你吸的血算在賬上的，記住了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니가 뽑아간 핏값도 너한테 청구할 생각이니까 그렇게 알고.","JPN":"姉さんに抜かれた血の代金もね。","ENG":"And for the blood Agnes took from me, too. You're covering that.","TWN":"姊姊拿走的血債也會算在你頭上的，就這樣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그런 게 어딨어요!","JPN":"そんな！","ENG":"That's not fair!","TWN":"哪有這樣的！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"세상에 공짜가 어디 있어? 닥치고 얌전히 피값이나 내놔.","JPN":"この世にただより高い物はない！　大人しくお金を出しなさい。","ENG":"Nothing in life is free. Now shut up and pay your blood debt.","TWN":"這世上哪有免費的東西？閉嘴，乖乖交出你的血債吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"으…… 으…….","JPN":"う……う……","ENG":"Ooh... Ooh...","TWN":"呃……呃……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"못 갚겠으면 몸으로라도 갚아!","JPN":"支払えないなら、体で払え！","ENG":"Can't pay? Then work it off.","TWN":"還不起的話就用身體來還！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"히, 히이익!!","JPN":"ひ、ひいっ！","ENG":"E-eeek!","TWN":"啊，啊啊啊！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"멍멍아, 놀리는 건 그쯤 해.","JPN":"ワンちゃん、からかうのはそれくらいにしなさい。","ENG":"Puppy, that's enough teasing.","TWN":"狗狗，別再捉弄人了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"놀리는 게 아니라 진심인데요.","JPN":"からかってるんじゃなくて本気なんですけど。","ENG":"Who said I was joking?","TWN":"我不是在逗你，我是認真的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"내가 햄스터한테 받을 게 있다고 했잖아.","JPN":"ハムスターちゃんから受け取るものがあるって言ったでしょう。","ENG":"I told you, I have something to collect from the hamster.","TWN":"我說過我有東西要跟倉鼠拿。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 자료들이 쓸만하면 여기 머무는 걸 허락해 줄게.","JPN":"その資料を見て、価値があると思ったらここにいさせてあげるわ。","ENG":"If the information is valuable, she can stay.","TWN":"如果那些資料有用的話，我會允許你留在這裡。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네. 루드윅의 연구 자료를 전부 갖고 오라고 하셨죠?","JPN":"はい。ルードヴィヒの研究資料を全部持ってくるようにってことでしたね。","ENG":"Right... You asked for all of Ludwig's research.","TWN":"好，你叫我把路易的研究資料全部帶過來，對吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 자식 연구 자료는 왜요?","JPN":"あいつの研究資料なんかどこに使うんですか？","ENG":"That jerk's research?","TWN":"那傢伙的研究資料？為什麼？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"학회에서 갖고 있는 지식이랑 별반 다를 거 없을 것 같은데.","JPN":"学会が持ってる知識と大差ないと思いますけど。","ENG":"The Society probably has the same information.","TWN":"和學會掌握的知識沒什麼兩樣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"우리는 찾지 못한 것을 발견했을 수도 있으니까.","JPN":"私たちがまだ見つけていないものを見つけているかもしれないからね。","ENG":"Perhaps. Or maybe, he discovered something we didn't.","TWN":"我們可能發現我們未曾找到的東西。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"어쩌면 너희들의 병을 해결할 수 있을지도 모르고.","JPN":"もしかすると、あなたたちの病気を治す方法がわかるかもしれないし。","ENG":"Something that could cure your sickness.","TWN":"或許能解決你們的病。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"한동안은 자료를 해석하느라 바쁠 것 같네.","JPN":"しばらくは資料の分析で忙しくなるわ。","ENG":"Either way, I'll be busy analyzing it for a while.","TWN":"我可能會忙於解讀資料一段時間。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"근데 이렇게 덜컥 받아줘도 되는 거예요?","JPN":"でも、こんな簡単に受け入れて大丈夫ですか？","ENG":"And you're just letting her stay?","TWN":"但是這樣一下子收下可以嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"성황청이라니까요.","JPN":"聖皇庁なんですよ？","ENG":"I'm telling you, she's from the Holy Curia.","TWN":"是聖皇廳欸。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"다 방법이 있어. 깊게 알려고 하지 마.","JPN":"手はあるわ。あまり勘ぐらないことね。","ENG":"I have my ways. Don't ask too many questions.","TWN":"我自有辦法，不用深究。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"앞으로 너희는 2인 1조로 종교학부의 생활비를 조달할 거야.","JPN":"これからあなたたちには2人1組になって、宗教学部の生活費を調達してもらうわ。","ENG":"From now on, the two of you will work together to fund the Religion Department.","TWN":"從現在開始，你們將兩人一組籌集宗教學院的生活費。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"두 명이니까 버는 돈도 두 배가 됐으면 좋겠네~","JPN":"2人だから収入も2倍になるといいわね～","ENG":"Two people mean twice the earnings, right?","TWN":"因為是兩個人，所以賺的錢也能翻倍就好了~"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……맘대로 해요. 모르겠다. 이제.","JPN":"……もう知らない。好きにしてください。","ENG":"...Do whatever you want. I don't care anymore.","TWN":"……隨你的便。我不管了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"좋아요!","JPN":"わかりました！","ENG":"Sounds great!","TWN":"好的！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"우왁! 달라붙지 마!","JPN":"うわっ！　くっつくなって！","ENG":"Whoa! Get off of me!","TWN":"嗚哇！不要黏著我！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 오늘부터 한 식구가 된 거죠?","JPN":"じゃあこれからは家族ですよね？","ENG":"That means we're family now, right?","TWN":"那麼從今天開始我們就是一家人了？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그런 의미로 피를 한 번만…….","JPN":"というわけで、血を1回だけ……","ENG":"Then to commemorate… will you give me your blood...?","TWN":"那樣的話，能不能讓我吸一口你的血……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"얘 완전히 눈이 돌아갔잖아!","JPN":"こいつ完全に目がイってる！","ENG":"She's completely lost it!","TWN":"這傢伙完全瘋了！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니! 얘 좀 붙잡아 봐요!","JPN":"姉さん！　こいつ何とかしてください！","ENG":"Please! Get her off me!","TWN":"姊姊！快抓住她！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니이!","JPN":"姉さーん！","ENG":"PLEASE!!!","TWN":"姊姊！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"후후, 북적북적하니까 좋네.","JPN":"ふふ、賑やかでいいわね。","ENG":"Haha, It's nice to have a lively house.","TWN":"呵呵，這麼熱鬧真不錯。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"……꽤 그리웠는데.","JPN":"……懐かしいわ。","ENG":"I... kind of missed this.","TWN":"……我很想念你。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};